/// A single AES-GCM test vector with key, IV, plaintext, AAD, and expected
/// ciphertext + authentication tag.
class AesGcmVector {
  final String description;
  final Uint8List key;
  final Uint8List iv;
  final Uint8List plaintext;
  final Uint8List aad;
  final Uint8List ciphertext;
  final Uint8List tag;

  const AesGcmVector({
    required this.description,
    required this.key,
    required this.iv,
    required this.plaintext,
    required this.aad,
    required this.ciphertext,
    required this.tag,
  });
}

